funcs.test_matches_phone_number_with_various_s:
@pytest.mark.parametrize("sender_key", ["sender", "direction"])
@pytest.mark.parametrize("sender_value", ["user", "tenant", "outbound", "ai", "USER", "Tenant"])
def test_matches_phone_number_with_various_senders_and_keys(sender_key, sender_value):
    # mobile_number with country code +44, normalized to local 0 prefix
    persona = {"mobile_number": "+44 7123 456789"}
    # content contains local number digits inside a sentence
    messages = [{
        sender_key: sender_value,
        "message": "Call me at 07123456789 tomorrow"
    }]
    # Should return True because local_number digits appear in message content digits
    assert phone_shared_state(messages, persona, None) is True

funcs.test_skips_messages_with_unrecognized_se:
def test_skips_messages_with_unrecognized_senders_and_fallback_content_key():
    persona = {"mobile_number": "07123456789"}
    messages = [
        {"sender": "unknown", "message": "07123456789"},  # sender not in allowed set, skip
        {"direction": "user", "content": "My number is 07123456789"},  # fallback to content key
        {"direction": "bot", "message": "07123456789"},  # sender not allowed, skip
    ]
    # Only second message counts, so returns True
    assert phone_shared_state(messages, persona, None) is True

